#define NOT_TENB 0
#define IS_TENB  1

#define TEN_WAIT_LOAD_0     0x001
#define TEN_WAIT_LOAD_1     0x002
#define TEN_WAIT_LOAD_L2_0  0x004
#define TEN_WAIT_LOAD_L2_1  0x008
#define TEN_WAIT_PREFETCH_0 0x010
#define TEN_WAIT_PREFETCH_1 0x020
#define TEN_WAIT_CACHEOP    0x040
#define TEN_WAIT_FMA        0x080
#define TEN_WAIT_STORE      0x100
#define TEN_WAIT_REDUCE     0x200
#define TEN_WAIT_QUANT      0x400
#define NO_TEN_WAIT         0x000


void print_ten_seq(CpuResource * cpu_resource, unum_t *ops, unum_t num_ops) {
   for (int i = 0; i < num_ops; i++) {
      switch(ops[i]) {
         case TFMA_OP:
            printf("cpuid: %d, seq[%d] = TFMA\n", snp_cpu_id(cpu_resource), i);
            break;
         case TLOAD_OP:
            printf("cpuid: %d, seq[%d] = TLOAD\n", snp_cpu_id(cpu_resource), i);
            break;
         case TFMA_TENB_OP:
            printf("cpuid: %d, seq[%d] = TFMA TENB\n", snp_cpu_id(cpu_resource), i);
            break;
         case TLOAD_TENB_OP:
            printf("cpuid: %d, seq[%d] = TLOAD TENB\n", snp_cpu_id(cpu_resource), i);
            break;
         case TQUANT_OP:
            printf("cpuid: %d, seq[%d] = TQUANT\n", snp_cpu_id(cpu_resource), i);
            break;
         case TSTORE_OP:
            printf("cpuid: %d, seq[%d] = TSTORE\n", snp_cpu_id(cpu_resource), i);
            break;
         case TREDUCE_OP:
            printf("cpuid: %d, seq[%d] = TREDUCE\n", snp_cpu_id(cpu_resource), i);
            break;
         case TSTORE_SCP_OP:
            printf("cpuid: %d, seq[%d] = TSTORE SCP\n", snp_cpu_id(cpu_resource), i);
            break;
         default:
            printf("cpuid: %d, seq[%d] = %d\n", snp_cpu_id(cpu_resource), i, ops[i]);
            break;
      }
   }
}
