void init_data_struct(unum_t *data_struct, const unum_t data_struct_size, const unum_t not_used_type) {
   for (int i = 0; i < data_struct_size; i++) {
      data_struct[i] = not_used_type;
   }
}
void init_l1scp(unum_t *l1_scp) {
   init_data_struct(l1_scp, L1SCP_SIZE, L1SCP_NOT_USED);
}
void init_vpu_rf(unum_t *vpu_rf) {
   init_data_struct(vpu_rf, VPU_RF_SIZE, VPU_RF_NOT_USED);
   // Reserve registers for Sting usage
   vpu_rf[26] = VPU_RF_SHARED;
   vpu_rf[27] = VPU_RF_SHARED;
   vpu_rf[30] = VPU_RF_SHARED;
   vpu_rf[31] = VPU_RF_SHARED;
}
void print_vpu_rf(unum_t *vpu_rf, char* msg) {
   for (int i = 0; i < VPU_RF_SIZE; i++) {
      if (vpu_rf[i] == VPU_RF_NOT_USED) {
         printf("%s RF(0x%llx)[%d]: VPU_RF_NOT_USED\n", msg, vpu_rf, i);
      }
      else if (vpu_rf[i] == VPU_RF_SHARED) {
         printf("%s RF(0x%llx)[%d]: VPU_RF_SHARED\n", msg, vpu_rf, i);
      }
      else if (vpu_rf[i] == VPU_RF_MODIFIED) {
         printf("%s RF(0x%llx)[%d]: VPU_RF_MODIFIED\n", msg, vpu_rf, i);
      }
   }
}
unum_t init_l1scp_ptr(CpuResource * cpu_resource) {
   unum_t * l1scp;
   l1scp = (unum_t*) calloc(L1SCP_SIZE, sizeof(unum_t));
   init_l1scp(l1scp);
   return (unum_t) l1scp;
}
unum_t init_vpu_rf_ptr(CpuResource * cpu_resource) {
   unum_t * vpu_rf;
   vpu_rf = (unum_t*) calloc(VPU_RF_SIZE, sizeof(unum_t));
   init_vpu_rf(vpu_rf);
   return (unum_t) vpu_rf;
}
unum_t init_tensor_sequence(CpuResource * cpu_resource, unum_t num_ops) {
   csr_op * ten_seq = (csr_op*) calloc(num_ops+1, sizeof(csr_op));
   return (unum_t) ten_seq;
}
std::vector<unum_t> set_tensor_enc(CpuResource * cpu_resource) {

   std::set <unum_t> avoid_ops;
   std::vector <unum_t> ten_seq_enc;

   if (ET_L2SCP.INCL_TL_L2SCP_OPS == 0) {
         // If L2SCP is part of the Sting MEM_SET, we must avoid TL L2SCP operations
         avoid_ops.insert(TLOAD_L2_OP);
   }

   // Avoid RTLMIN-6215
   if (ET_TEST_ENV.SCP_ENABLE == 0) {
      // RTLMIN-6215 describes an issue when the L1SCP is disabled and we try to do a tensor quant with a SCP transformation
      // the problem is that the tensor_error bit generated by Thread0 ends up written in the tensor_error of Thread1
      // The workaround is to not render tensor quant ops at all if the L1SCP is not enabled
      avoid_ops.insert(TQUANT_OP);
   }

   const unum_t active_minions = snp_get_soc_active_minions(cpu_resource);
   const unum_t treduce_qual = active_minions > 1;
   if (!treduce_qual) {
      // To use TensorReduce we must run with at least 2 minions
      avoid_ops.insert(TREDUCE_OP);
   }

   for (int i = 0; i < TENSOR_OPS_SIZE; i++) {
      if (!avoid_ops.count(i)) ten_seq_enc.push_back(i);
   }
   return ten_seq_enc;
}

unum_t free_l1scp_ptr(CpuResource * cpu_resource, unum_t l1scp_ptr) {
   unum_t * l1scp = (unum_t*) l1scp_ptr;
   free(l1scp);
   return 1;
}
unum_t free_vpu_rf_ptr(CpuResource * cpu_resource, unum_t vpu_rf_ptr) {
   unum_t * vpu_rf = (unum_t*) vpu_rf_ptr;
   free(vpu_rf);
   return 1;
}
unum_t free_tensor_sequence(CpuResource * cpu_resource, unum_t ten_seq_ptr) {
   csr_op * ten_seq = (csr_op*) ten_seq_ptr;
   free(ten_seq);
   return 1;
}
unum_t get_clean_tenb_tfma(CpuResource * cpu_resource, unum_t l1scp_ptr, unum_t vpu_rf_ptr, unum_t ten_seq_ptr, unum_t num_ops) {
   unum_t ret = 0;
   unum_t need_clean = 0;
   unum_t last_tl_tenb_csr_val;
   csr_op * ten_seq = (csr_op*) ten_seq_ptr;
   for (int i = 0; i < num_ops; i++) {
      if (ten_seq[i].op_type == TLOAD_TENB_OP) {
         need_clean = 1;
         last_tl_tenb_csr_val = ten_seq[i].csr_val;
      }
      else if (ten_seq[i].op_type == TFMA_TENB_OP) need_clean = 0;
   }
   if (need_clean) {
      unum_t * l1_scp = (unum_t*) l1scp_ptr;
      unum_t * vpu_rf = (unum_t*) vpu_rf_ptr;
      unum_t stub[] = {TFMA_TENB_OP};
      ret = snp_seq_tfma_base(cpu_resource, l1_scp, vpu_rf, stub, 0, 1, IS_TENB);
      unum_t bias = snp_urandrange(cpu_resource, 0, 12);
      // Sometimes clean TL TenB using a wrong config
      if (bias != 0) {
         unum_t tl_bits = snp_get_bits(cpu_resource, last_tl_tenb_csr_val, 3, 0);
         ret = snp_set_bits(cpu_resource, ret, 50, 47, tl_bits);
      }
      csr_op clean_tfma;
      clean_tfma.op_type = TFMA_TENB_OP;
      clean_tfma.csr_val = ret;
      ten_seq[num_ops] = clean_tfma;
   }
   return ret;
}
unum_t get_clean_tenb_twait(CpuResource * cpu_resource, unum_t ten_seq_ptr, unum_t num_ops) {
   csr_op * ten_seq = (csr_op*) ten_seq_ptr;
   return get_tfma_dependency(cpu_resource, ten_seq, 0, num_ops);
}
unum_t glbl_get_csr_val_from_op(CpuResource * cpu_resource, unum_t *ten_seq, unum_t idx, unum_t num_ops, unum_t* l1_scp, unum_t* vpu_rf) {
   unum_t tensor_op = ten_seq[idx];
   unum_t csr_val = -1;
   switch (tensor_op) {
      case TLOAD_OP:
         csr_val = snp_seq_tload_base(cpu_resource, ten_seq, idx, num_ops, l1_scp, NOT_TENB);
         break;
      case TFMA_OP:
         csr_val = snp_seq_tfma_base(cpu_resource, l1_scp, vpu_rf, ten_seq, idx, num_ops, NOT_TENB);
         break;
      case TLOAD_TENB_OP:
         csr_val = snp_seq_tload_base(cpu_resource, ten_seq, idx, num_ops, l1_scp, IS_TENB);
         break;
      case TFMA_TENB_OP:
         csr_val = snp_seq_tfma_base(cpu_resource, l1_scp, vpu_rf, ten_seq, idx, num_ops, IS_TENB);
         break;
      case TQUANT_OP:
         csr_val = snp_seq_tquant_base(cpu_resource, l1_scp, vpu_rf, ten_seq, idx, num_ops);
         break;
      case TSTORE_OP:
         csr_val = snp_seq_tstore_base(cpu_resource, vpu_rf, ten_seq, idx, num_ops);
         break;
      case TREDUCE_OP:
         csr_val = glbl_snp_seq_treduce_base(cpu_resource, vpu_rf);
         break;
      case TSTORE_SCP_OP:
         csr_val = snp_seq_ts_scp_base(cpu_resource, l1_scp);
         break;
      case TCONV_SIZE_OP:
         csr_val = snp_seq_tconv_size_base(cpu_resource);
         break;
      case TCONV_CTRL_OP:
         csr_val = snp_seq_tconv_ctrl_base(cpu_resource);
         break;
      case TLOAD_L2_OP:
         csr_val = snp_seq_tload_l2_base(cpu_resource);
         break;
   }
   assert(csr_val != -1);
   return csr_val;
}
void set_empty_data_ranges(std::vector<data_region> &free_regions, unum_t *data_struct, const unum_t data_struct_size, const unum_t not_used_type, unum_t op_type, unum_t assert_size) {

   assert(free_regions.size() == 0);
   int it = 0;

   data_region curr_region;
   while (it < data_struct_size) {
      while ((data_struct[it] != not_used_type) && (data_struct[it] != op_type) && (it < data_struct_size)) it++;
      if (it < data_struct_size) {
         curr_region.head = it;
         while (((data_struct[it] == not_used_type) || (data_struct[it] == op_type))  && (it < data_struct_size)) it++;
         curr_region.tail = it-1;
         free_regions.push_back(curr_region);
      }
   }
   if (assert_size) assert(free_regions.size() != 0);
}
data_region get_empty_l1scp_range(CpuResource * cpu_resource, unum_t *l1_scp, unum_t op_type) {
   std::vector<data_region> free_regions;
   set_empty_data_ranges(free_regions, l1_scp, L1SCP_SIZE, L1SCP_NOT_USED, op_type, 1);
   unum_t ret_region = snp_urandrange(cpu_resource, 0, free_regions.size());
   return free_regions[ret_region];
}
void regions_pre_booking(CpuResource * cpu_resource, const unum_t *ten_seq, unum_t num_ops, unum_t target_op, unum_t not_used_op, unum_t *data_reg, unum_t data_reg_size, const std::set<unum_t>& ops_set) {
   unum_t booking_size = (data_reg_size - (TREDUCE_MAX_REGS*2))/3;

   const auto ten_seq_end = ten_seq + num_ops;
   const auto is_target_op = [&ops_set](unum_t op) -> bool { return ops_set.count(op); };

   const unum_t contains_target_op = std::find_if(ten_seq, ten_seq_end, is_target_op) != ten_seq_end;
   if (contains_target_op) {
      std::vector<data_region> target_regions;
      set_empty_data_ranges(target_regions, data_reg, data_reg_size, not_used_op, target_op, 1);
      const auto too_small = [booking_size](data_region idx) -> bool {
         unum_t reg_size = idx.tail - idx.head + 1;
         return reg_size < booking_size;
      };
      // Filter out the regions that are too small
      target_regions.erase(remove_if(target_regions.begin(), target_regions.end(), too_small), target_regions.end());
      assert(target_regions.size() > 0);
      // Select a random region
      unum_t booked_idx = snp_urandrange(cpu_resource, 0, target_regions.size());
      data_region booked_region = target_regions[booked_idx];
      // Randomly choose the start of the booked region (that must be inside 'booked_region')
      unum_t start = snp_urandrange(cpu_resource, booked_region.head, booked_region.tail - (booking_size-1) + 1);
      assert((0 <= start) && (start < data_reg_size));
      unum_t end = start + (booking_size-1);
      assert((0 <= end) && (end < data_reg_size));
      // Book the region in the data regions model
      const auto book_region = [target_op, not_used_op](unum_t i) { assert((i == not_used_op) || (i == target_op)); return target_op; };
      std::transform(data_reg+start, data_reg+end, data_reg+start, book_region);
   }
}
void vpu_rf_pre_booking(CpuResource * cpu_resource, const unum_t *ten_seq, unum_t num_ops, unum_t * vpu_rf) {
   // We assume that this is called after processing all the TensorReduces, so we can skip TREDUCE in the 'sets'
   std::set<unum_t> read_ops {TSTORE_OP};
   unum_t vpu_rf_book_size = VPU_RF_SIZE-6; // 6 registers (f26, f27, f28, f29, f30, f31) are already reserved for Sting RANDINST reads
   regions_pre_booking(cpu_resource, ten_seq, num_ops, VPU_RF_SHARED, VPU_RF_NOT_USED, vpu_rf, vpu_rf_book_size, read_ops);
   std::set<unum_t> write_ops {TFMA_OP, TFMA_TENB_OP, TQUANT_OP};
   regions_pre_booking(cpu_resource, ten_seq, num_ops, VPU_RF_MODIFIED, VPU_RF_NOT_USED, vpu_rf, vpu_rf_book_size, write_ops);
}
void l1scp_pre_booking(CpuResource * cpu_resource, const unum_t *ten_seq, unum_t num_ops, unum_t * l1_scp) {
   std::set<unum_t> read_ops {TFMA_OP, TFMA_TENB_OP, TQUANT_OP, TSTORE_SCP_OP};
   regions_pre_booking(cpu_resource, ten_seq, num_ops, L1SCP_SHARED, L1SCP_NOT_USED, l1_scp, L1SCP_SIZE, read_ops);
   // L1SCP write operations (TL) cannot share regions, therefore it makes no sense to pre-book a L1SCP_MODIFIED region
}
std::vector<data_region> get_fair_empty_regions(CpuResource * cpu_resource, unum_t *data_reg, unum_t data_reg_size, unum_t data_reg_not_used, const unum_t *ten_seq, unum_t idx, unum_t num_ops, unum_t region_op, const std::set<unum_t>& read_ops, const std::set<unum_t> &write_ops) {
   std::vector<data_region> free_regions;
   set_empty_data_ranges(free_regions, data_reg, data_reg_size, data_reg_not_used, region_op, 1);

   // In order to make sure that there is enough space for every operation accessing to the region
   // we compute how many operations writes the DATA_REGION (these operations cannot share the regions)
   // and how many operations reads the DATA_REGION (these operations can share the regions).
   const auto ten_seq_end = ten_seq + num_ops;
   const auto is_write_op = [&write_ops](unum_t op) -> bool { return write_ops.count(op); };
   const auto is_read_op = [&read_ops](unum_t op) -> bool { return read_ops.count(op); };
   // Compute how many future writes there are
   const unum_t future_write_reg = std::count_if(&ten_seq[idx], ten_seq_end, is_write_op);
   // Compute if there is at least one read
   const unum_t future_read_reg = std::find_if(&ten_seq[idx], ten_seq_end, is_read_op) != ten_seq_end;

   const unum_t num_regions = future_write_reg + future_read_reg;

   // We have to ensure that there are at least 'num_regions' available in the free regions
   // if not, then we slice the current regions in order to have enough regions for every
   // future operation accessing to the DATA_REGION
   const auto slice_region = [&free_regions, cpu_resource](unum_t victim_idx) {
      // slice region logic
      data_region victim = free_regions[victim_idx];
      if (victim.head != victim.tail) {
         unum_t new_tail = snp_urandrange(cpu_resource, victim.head, victim.tail);
         free_regions[victim_idx].tail = new_tail;
         victim.head = new_tail + 1;
         assert(victim.head <= victim.tail);
         free_regions.push_back(victim);
      }
   };
   unum_t while_cnt = 100; // emergency counter just in case we stuck in a infinite loop
   while (free_regions.size() < num_regions) {
      unum_t rand_idx = snp_urandrange(cpu_resource, 0, free_regions.size());
      slice_region(rand_idx);
      while_cnt--;
      assert(while_cnt > 0);
   }
   return free_regions;
}
data_region tl_get_empty_l1scp_range(CpuResource * cpu_resource, unum_t *l1_scp, unum_t *ten_seq, unum_t idx, unum_t num_ops) {

   std::set<unum_t> read_ops {TFMA_OP, TFMA_TENB_OP, TQUANT_OP, TSTORE_SCP_OP};
   std::set<unum_t> write_ops {TLOAD_OP};
   // Due to Write after Write dependencies not being handled correctly by the RTL
   // in back to back TL scenarios, we will use L1SCP_NOT_USED to always get a non-used region
   std::vector<data_region> fair_free_regions = get_fair_empty_regions(cpu_resource, l1_scp, L1SCP_SIZE, L1SCP_NOT_USED, ten_seq, idx, num_ops, L1SCP_NOT_USED, read_ops, write_ops);
   unum_t ret_region = snp_urandrange(cpu_resource, 0, fair_free_regions.size());
   return fair_free_regions[ret_region];
}
data_region get_empty_vpu_rf_range(CpuResource * cpu_resource, unum_t *vpu_rf, unum_t op_type, unum_t *ten_seq, unum_t idx, unum_t num_ops) {
   std::set<unum_t> write_ops {TFMA_OP, TFMA_TENB_OP, TQUANT_OP, TREDUCE_OP};
   std::set<unum_t> read_ops {TSTORE_OP, TREDUCE_OP};
   std::vector<data_region> fair_free_regions = get_fair_empty_regions(cpu_resource, vpu_rf, VPU_RF_SIZE, VPU_RF_NOT_USED, ten_seq, idx, num_ops, op_type, read_ops, write_ops);
   unum_t ret_region = snp_urandrange(cpu_resource, 0, fair_free_regions.size());
   return fair_free_regions[ret_region];
}
data_region get_empty_vpu_tfma_range(CpuResource * cpu_resource, unum_t *vpu_rf, unum_t op_type, unum_t *ten_seq, unum_t idx, unum_t num_ops) {
   std::set<unum_t> write_ops {TFMA_OP, TFMA_TENB_OP, TQUANT_OP, TREDUCE_OP};
   std::set<unum_t> read_ops {TSTORE_OP, TREDUCE_OP};
   std::vector<data_region> fair_free_regions = get_fair_empty_regions(cpu_resource, vpu_rf, VPU_RF_SIZE, VPU_RF_NOT_USED, ten_seq, idx, num_ops, op_type, read_ops, write_ops);
   if (fair_free_regions.size() == 0) {
      // If there is no free regions, then we return a 'stub' region. This is fine for TFMA operations
      // because later on, we will force the operation to be a TIMA that writes to tenc instead of VPU RF
      data_region stub;
      stub.head = 0xbad;
      stub.tail = 0xbad;
      return stub;
   }
   return fair_free_regions[0];
}
data_region get_empty_vpu_reduce_range(CpuResource * cpu_resource, unum_t *vpu_rf, unum_t num_regs, unum_t op_type) {
   std::vector<data_region> free_regions;
   set_empty_data_ranges(free_regions, vpu_rf, VPU_RF_SIZE, VPU_RF_NOT_USED, op_type, 1);

   std::vector<data_region> qual_regions;
   assert(free_regions.size() != 0);
   for (int i = 0; i < free_regions.size(); i++) {
      if ((free_regions[i].tail - free_regions[i].head + 1) >= num_regs) {
         qual_regions.push_back(free_regions[i]);
      }
   }
   assert(qual_regions.size() != 0);
   unum_t ret_region = snp_urandrange(cpu_resource, 0, qual_regions.size());
   return qual_regions[ret_region];
}
void do_fisher_yates(CpuResource * cpu_resource, csr_op* ten_ops_seq, unum_t seq_size, unum_t* ops_idx) {
   // Precondition: first elements are always a tensor_reduce
   // Find the first position that it is not a Tensor Reduce operation
   int head = 0;
   unum_t selfcheck_treduce[seq_size];
   while ((ten_ops_seq[head].op_type == TREDUCE_OP) && (head < seq_size)) {
      selfcheck_treduce[head] = ten_ops_seq[head].csr_val;
      head++;
   }

   // Do Fisher Yates for the all the operations that are not a reduce
   for (int i = head; i <= seq_size-2; i++) {
      unum_t j = snp_urandrange(cpu_resource, head, seq_size);
      csr_op csr_tmp = ten_ops_seq[i];
      ten_ops_seq[i] = ten_ops_seq[j];
      ten_ops_seq[j] = csr_tmp;
   }

   // Shuffle the Tensor Reduces into the sequence but always keeping the same order between reduces
   unum_t tr_tail = seq_size;
   for (int i = head-1; i >= 0; i--) {
      unum_t j = snp_urandrange(cpu_resource, i, tr_tail);
      csr_op csr_tmp = ten_ops_seq[i];
      ten_ops_seq[i] = ten_ops_seq[j];
      ten_ops_seq[j] = csr_tmp;
      tr_tail = j;
   }

   int j = 0;
   for (int i = 0; i < seq_size; i++) {
      ops_idx[i] = ten_ops_seq[i].op_type;
      if (ten_ops_seq[i].op_type == TREDUCE_OP) {
         assert(selfcheck_treduce[j] == ten_ops_seq[i].csr_val);
         j++;
      }
   }
}
void glbl_do_fisher_yates(CpuResource * cpu_resource, unum_t seq_size, unum_t* ops_idx) {
   for (int i = 0; i <= seq_size-2; i++) {
      unum_t j = snp_urandrange_glbl(cpu_resource, 0, seq_size);
      unum_t csr_tmp = ops_idx[i];
      ops_idx[i] = ops_idx[j];
      ops_idx[j] = csr_tmp;
   }
}
void pair_tconv_size_ctrl(CpuResource * cpu_resource, csr_op * ten_seq, unum_t num_ops) {
   int prev = -1;

   // There are two Tensor Convolution operations, Size and Ctrl. Both operations will modify the TensorMask
   // based on the Size/Ctrl that has been setup in the past. The approach we are following is to randomly
   // choose a Size value and constrain the Ctrl value based on the Size

   for (int i = 0; i < num_ops; i++) {
      if (ten_seq[i].op_type == TCONV_SIZE_OP) prev = ten_seq[i].csr_val;
      else if (ten_seq[i].op_type == TCONV_CTRL_OP) {
         // As there might be multiple Tensor Conv Size, we randomly choose between the previous one
         // or the next one happening in the future. There are 4 possible scenarios:
         //    1) No previous Conv Size: try to pair with the next Conv Size
         //    2) No next Conv Size: try to pair with the previous Conv Size
         //    3) There is a previous and a next Conv Size: randomly choose one and pair
         //    4) No previous, no next Conv Size: leave the existing random value

         unum_t bias = 1;
         unum_t prev_found = (prev == -1) ? 0 : 1;
         if (prev_found) bias = snp_urandrange(cpu_resource, 0, 2);

         if (bias == 0) ten_seq[i].csr_val = snp_paired_tconv_ctrl_base(cpu_resource, prev);
         else {
            for (int j = i + 1; j < num_ops; j++) {
               // Find the next Conv Size
               if (ten_seq[j].op_type == TCONV_SIZE_OP) ten_seq[i].csr_val = snp_paired_tconv_ctrl_base(cpu_resource, ten_seq[j].csr_val);
            }
         }
      }
   }
}


////////////////////////////////////////////////////////////////////////////
//
//  Tensor Dependency Checkers
//
////////////////////////////////////////////////////////////////////////////
unum_t is_tfma_tena_executed(CpuResource * cpu_resource, csr_op * ten_seq, unum_t tfma_idx) {
   assert(ten_seq[tfma_idx].op_type == TFMA_OP);
   int i = tfma_idx - 1;
   unum_t reads_l1scp = get_tfma_ten_waits(cpu_resource, ten_seq[tfma_idx].csr_val) & READS_L1SCP;
   if (reads_l1scp) {
      while (i >= 0) {
         if ((ten_seq[i].op_type == TFMA_TENB_OP) || (ten_seq[i].op_type == TFMA_OP)) {
            return 1;
         }
         else if (ten_seq[i].op_type == TLOAD_TENB_OP) {
            return 0;
         }
         i--;
      }
   }
   return 1;
}
unum_t is_tfma_tenb_paired(CpuResource * cpu_resource, csr_op * ten_seq, unum_t tfma_idx) {
   assert(ten_seq[tfma_idx].op_type == TFMA_TENB_OP);
   int i = tfma_idx - 1;
   unum_t tfma_csr_val = ten_seq[tfma_idx].csr_val;
   unum_t tfma_bits = snp_get_bits(cpu_resource, tfma_csr_val, 50, 47);
   while (i >= 0) {
      if ((ten_seq[i].op_type == TFMA_TENB_OP) || (ten_seq[i].op_type == TFMA_OP)) {
         return 0;
      }
      else if (ten_seq[i].op_type == TLOAD_TENB_OP) {
         unum_t tl_tenb_csr_val = ten_seq[i].csr_val;
         unum_t tl_tenb_bits = snp_get_bits(cpu_resource, tl_tenb_csr_val, 3, 0);
         if (tfma_bits == tl_tenb_bits) return 1;
         else return 0;
      }
      i--;
   }
   return 0;
}
unum_t is_tfmaa_tlb_dependency(CpuResource * cpu_resource, csr_op * ten_seq, unum_t start, unum_t num_ops) {
   int i = start;
   unum_t num_tfma_tena = 0;
   while (i < num_ops)  {
      if (ten_seq[i].op_type == TFMA_OP) {
         if(is_tfma_tena_executed(cpu_resource, ten_seq, i)) num_tfma_tena++;
      }
      else if ((ten_seq[i].op_type == TLOAD_TENB_OP) && (num_tfma_tena != 0)) return 1;
      i++;
   }
   return 0;
}
unum_t get_tstore_scp_dependency(CpuResource * cpu_resource, csr_op * ten_seq, unum_t start, unum_t num_ops) {
   assert(ten_seq[num_ops].op_type == TSTORE_SCP_OP);
   int i = start;
   unum_t ten_wait = NO_TEN_WAIT;
   unum_t tfma_tenc = 0;
   while (i < num_ops)  {
      if ((ten_seq[i].op_type == TFMA_OP) || (ten_seq[i].op_type == TFMA_TENB_OP)) {
         unum_t not_error = (ten_seq[i].op_type == TFMA_OP) ? \
                            is_tfma_tena_executed(cpu_resource, ten_seq, i) :\
                            is_tfma_tenb_paired(cpu_resource, ten_seq, i);
         if (not_error) {
            tfma_tenc = (get_tfma_ten_waits(cpu_resource, ten_seq[i].csr_val) & WRITES_VPU_RF) == 0;
            if (((ten_wait & TEN_WAIT_QUANT) != 0) && tfma_tenc) {
               ten_wait = TEN_WAIT_QUANT | TEN_WAIT_FMA;
            }
            else {
               ten_wait = TEN_WAIT_FMA;
            }
         }
      }
      else if (ten_seq[i].op_type == TQUANT_OP) {
         unum_t tquant_is_nop = tquant_is_a_nop(cpu_resource, ten_seq[i].csr_val);
         if (!tquant_is_nop) {
            if (tfma_tenc) ten_wait = TEN_WAIT_QUANT | TEN_WAIT_FMA;
            else ten_wait = TEN_WAIT_QUANT;
         }
      }
      else if (ten_seq[i].op_type == TSTORE_SCP_OP) {
         // If there is another TENSOR STORE From SCP before this one and
         // there is no other TFMA or TQUANT in between, then a tensor wait is not needed
         // because the previous one would have waited already
         ten_wait = NO_TEN_WAIT;
         tfma_tenc = 0;
      }
      else if ((ten_seq[i].op_type == TSTORE_OP) && (!tfma_tenc)) {
         // If there is a TensorStore (not from SCP), you do not need to do a tensor wait, except if
         // previously another TensorFMA TenC happen. Imagine the following sequence:
         //
         //    * TFMA TenC -> TS -> TS SCP
         //
         // TS is not blocked by TFMA TenC because TFMA TenC do not write into the RF. It may happen that
         // TS finishes earlier than the TFMA TenC, so you have to wait for TFMA TenC to finish before the TS SCP
         unum_t not_error = get_tstore_ten_waits(cpu_resource, ten_seq[i].csr_val) & READS_VPU_RF;
         if (not_error) {
            ten_wait = NO_TEN_WAIT;
            tfma_tenc = 0;
         }
      }
      i++;
   }
   return ten_wait;
}
unum_t get_tfma_tquant_tsscp_dependency(CpuResource * cpu_resource, csr_op * ten_seq, unum_t start, unum_t num_ops) {
   int i = start;
   unum_t ten_wait = NO_TEN_WAIT;

   unum_t is_executed;
   if (ten_seq[num_ops].op_type == TFMA_OP) is_executed = is_tfma_tena_executed(cpu_resource, ten_seq, num_ops);
   else if (ten_seq[num_ops].op_type == TFMA_TENB_OP) is_executed = is_tfma_tenb_paired(cpu_resource, ten_seq, num_ops);
   else if (ten_seq[num_ops].op_type == TQUANT_OP) is_executed = !tquant_is_a_nop(cpu_resource, ten_seq[num_ops].csr_val);
   else assert("Operation must be TFMA/TQUANT type" && 0);

   if (is_executed) {
      while (i < num_ops)  {
         if (ten_seq[i].op_type == TSTORE_SCP_OP) ten_wait = TEN_WAIT_STORE;
         else if (ten_seq[i].op_type == TSTORE_OP) {
            is_executed = get_tstore_ten_waits(cpu_resource, ten_seq[i].csr_val) & READS_VPU_RF;
            // If there is another TENSOR STORE before this one and there is
            // no other TSTORE From SCP in between, then a tensor wait is not needed
            // because there is an implicit wait between Tensor Stores
            if (is_executed) ten_wait = NO_TEN_WAIT;
         }
         else if ((ten_seq[i].op_type == TFMA_OP) || (ten_seq[i].op_type == TFMA_TENB_OP)) {
            if (ten_seq[i].op_type == TFMA_OP) is_executed = is_tfma_tena_executed(cpu_resource, ten_seq, i);
            else is_executed = is_tfma_tenb_paired(cpu_resource, ten_seq, i);
            // If there is another TENSOR FMA before this one and there is
            // no other TSTORE From SCP in between, then a tensor wait is not needed
            // because the previous one would have waited already
            if (is_executed) ten_wait = NO_TEN_WAIT;
         }
         else if (ten_seq[i].op_type == TQUANT_OP) {
            is_executed = !tquant_is_a_nop(cpu_resource, ten_seq[i].csr_val);
            // If there is another TENSOR QUANT before this one and there is
            // no other TSTORE From SCP in between, then a tensor wait is not needed
            // because the previous one would have waited already
            if (is_executed) ten_wait = NO_TEN_WAIT;
         }
         i++;
      }
   }
   return ten_wait;
}
unum_t get_tfma_dependency(CpuResource * cpu_resource, csr_op * ten_seq, unum_t start, unum_t num_ops) {
   assert((ten_seq[num_ops].op_type == TFMA_OP) || (ten_seq[num_ops].op_type == TFMA_TENB_OP));
   return get_tfma_tquant_tsscp_dependency(cpu_resource, ten_seq, start, num_ops);
}
unum_t get_tquant_dependency(CpuResource * cpu_resource, csr_op * ten_seq, unum_t start, unum_t num_ops) {
   assert(ten_seq[num_ops].op_type == TQUANT_OP);
   return get_tfma_tquant_tsscp_dependency(cpu_resource, ten_seq, start, num_ops);
}
unum_t get_tenwait_value_from_idx(CpuResource * cpu_resource, unum_t idx, unum_t ten_seq_ptr, unum_t num_ops) {
   unum_t ret = NO_TEN_WAIT;
   csr_op *ten_seq = (csr_op*) ten_seq_ptr;
   if (ten_seq[idx].op_type == TLOAD_TENB_OP) {
      if (is_tfmaa_tlb_dependency(cpu_resource, ten_seq, 0, idx+1)) ret = TEN_WAIT_FMA;
   }
   else if (ten_seq[idx].op_type == TSTORE_SCP_OP) {
      ret = get_tstore_scp_dependency(cpu_resource, ten_seq, 0, idx);
   }
   else if ((ten_seq[idx].op_type == TFMA_OP) || (ten_seq[idx].op_type == TFMA_TENB_OP)) {
      ret = get_tfma_dependency(cpu_resource, ten_seq, 0, idx);
   }
   else if (ten_seq[idx].op_type == TQUANT_OP) {
      ret = get_tquant_dependency(cpu_resource, ten_seq, 0, idx);
   }
   return ret;
}


////////////////////////////////////////////////////////////////////////////
//
//  Workarounds to avoid known bugs
//
//     * Some of the workarounds are in the std::vector<unum_t> set_tensor_enc() method
//
////////////////////////////////////////////////////////////////////////////
unum_t get_glbl_rand_op(CpuResource * cpu_resource, std::vector<unum_t> &ten_seq_enc) {
   unum_t ret = snp_urandrange_glbl(cpu_resource, 0, ten_seq_enc.size());
   return ten_seq_enc[ret];
}
unum_t get_rand_op_excl(CpuResource * cpu_resource, unum_t excl_op, std::vector<unum_t> &ten_seq_enc) {
   // This function is used to get a random tensor operation that is different than 'excl_op'
   // This specific function also takes into account the global operations (e.g. Tensor Reduce)
   // as this operations requires to be present globally (in every thread), we must avoid them here
   unum_t ret = excl_op;
   while (ret == excl_op || ret == TREDUCE_OP) {
      unum_t idx = snp_urandrange(cpu_resource, 0, ten_seq_enc.size());
      ret = ten_seq_enc[idx];
   }
   return ret;
}
void limit_num_treduces(CpuResource * cpu_resource, unum_t *ops, unum_t num_ops, std::vector<unum_t> &ten_seq_enc) {
   //This is not a bug, but due to the difficulty to generate a tensor reduce with the same
   //config among all the threads, we are limiting the number of reduces to 2
   //This is needed because we cannot play around with the number of registers in tensor reduce
   int treduce_count = 0;
   for (int i = 0; i < num_ops; i++) {
      if (ops[i] == TREDUCE_OP) {
         treduce_count++;
         if (treduce_count > 2) {
            ops[i] = get_rand_op_excl(cpu_resource, TREDUCE_OP, ten_seq_enc);
         }
      }
   }
}


////////////////////////////////////////////////////////////////////////////
//
//  Tensor Operations Sequence
//  /!\ Not intended to be called from a Sting Snippet
//
////////////////////////////////////////////////////////////////////////////
unum_t order_ops_by_type(unum_t it_start, unum_t op_type, unum_t *ops, unum_t num_ops) {
   unum_t ret = it_start;
   for (int i = it_start; i < num_ops; i++) {
      int j = i + 1;
      int found = (ops[i] == op_type);
      while (!found && j < num_ops) {
         if (ops[j] == op_type) {
            unum_t tmp = ops[i];
            ops[i] = ops[j];
            ops[j] = tmp;
            found = 1;
         }
         j++;
      }
      if (found) ret = i + 1;
   }
   return ret;
}
void order_ops_by_priority(unum_t *ops, unum_t num_ops) {

   int tmp = 0;
   int head, tail;

   head = 0;
   int ops_priority[6] = {TREDUCE_OP, TLOAD_OP, TFMA_OP, TSTORE_OP, TLOAD_TENB_OP, TFMA_TENB_OP};

   for (int i = 0; i < 6; i++) {
      tail = order_ops_by_type(head, ops_priority[i], ops, num_ops);
      for (int j = head; j < tail; j++) assert(ops[j] == ops_priority[i]);
      head = tail;
   }
}
void selfcheck_decode(CpuResource * cpu_resource, unum_t *ops, unum_t num_ops, unum_t encoded_seq) {
   for (int i = 0; i < num_ops; i++) {
      unum_t tmp = decode_tensor_ops_sequence(cpu_resource, encoded_seq, i);
      assert(tmp == ops[i]);
   }
}
unum_t encode_tensor_ops_sequence(CpuResource * cpu_resource, unum_t *ops, unum_t num_ops){
   int ret = 0;
   for (int i = 0; i < num_ops; i++) {
      ret = ret | (ops[i] << (i * BITS_PER_OP));
   }
   return ret;
}
unum_t decode_tensor_ops_sequence(CpuResource * cpu_resource, unum_t encoded_seq, unum_t op_pos){
   int ret = encoded_seq;
   ret = ret >> (op_pos * BITS_PER_OP);
   ret = ret & OP_BITS_MASK;
   return ret;
}
void glbl_set_rand_sequence(CpuResource * cpu_resource, unum_t* ops, unum_t num_ops, std::vector<unum_t> &ten_seq_enc) {
   const unum_t active_minions = snp_get_soc_active_minions(cpu_resource);
   const unum_t treduce_qual = active_minions > 1;
   for (int i = 0; i < num_ops; i++) {
      ops[i] = get_glbl_rand_op(cpu_resource, ten_seq_enc);
      if ((ops[i] != TREDUCE_OP) || (!treduce_qual)) {
         ops[i] = get_rand_op_excl(cpu_resource, TREDUCE_OP, ten_seq_enc);
      }
   }
}
void glbl_set_unique_sequence(CpuResource * cpu_resource, unum_t* ops, unum_t num_ops, std::vector<unum_t> &ten_seq_enc) {
   const unum_t active_minions = snp_get_soc_active_minions(cpu_resource);
   const unum_t treduce_qual = active_minions > 1;
   unum_t it = 0;
   unum_t unique_seq[ten_seq_enc.size()];
   for (int i = 0; i < ten_seq_enc.size(); i++) {
      unum_t ten_op = ten_seq_enc[i];
      if (treduce_qual || (ten_op != TREDUCE_OP)) {
         unique_seq[it] = ten_op;
         it++;
      }
   }
   // FUTURE: Not force everybody execute the same sequence
   assert(num_ops <= it);
   glbl_do_fisher_yates(cpu_resource, it, unique_seq);
   for (int i = 0; i < num_ops; i++) ops[i] = unique_seq[i];
}


////////////////////////////////////////////////////////////////////////////
//
//  C API functions called from a Sting Snippet
//
////////////////////////////////////////////////////////////////////////////

// Any Tensor Op Snippet
unum_t glbl_snp_set_tensor_ops_sequence(CpuResource * cpu_resource, unum_t l1scp_ptr, unum_t vpu_rf_ptr, unum_t ten_seq_ptr, unum_t num_ops, unum_t rand_init) {
   unum_t ret = 0;
   unum_t ops[num_ops]= {0};

   unum_t *l1_scp = (unum_t*) l1scp_ptr;
   unum_t *vpu_rf = (unum_t*) vpu_rf_ptr;
   csr_op *ten_seq = (csr_op*) ten_seq_ptr;

   std::vector<unum_t> ten_seq_enc = set_tensor_enc(cpu_resource);

   unum_t unique_bias = snp_urandrange_glbl(cpu_resource, 0, 2);
   if (unique_bias == 0) glbl_set_rand_sequence(cpu_resource, ops, num_ops, ten_seq_enc);
   else glbl_set_unique_sequence(cpu_resource, ops, num_ops, ten_seq_enc);

   limit_num_treduces(cpu_resource, ops, num_ops, ten_seq_enc);
   order_ops_by_priority(ops, num_ops);

   // Process first the RAND_GLBL operations (e.g. TensorReduce)
   int idx = 0;
   while (ops[idx] == TREDUCE_OP) {
      unum_t csr_val = glbl_get_csr_val_from_op(cpu_resource, ops, idx, num_ops, l1_scp, vpu_rf);
      ten_seq[idx].op_type = ops[idx];
      ten_seq[idx].csr_val = csr_val;
      idx++;
   }

   // Pre booking to make sure that at least there is one READ and one WRITE region on the L1SCP/VPURF
   vpu_rf_pre_booking(cpu_resource, ops, num_ops, vpu_rf);
   l1scp_pre_booking(cpu_resource, ops, num_ops, l1_scp);

   // Process the rest of operations
   for (int i = idx; i < num_ops; i++) {
      unum_t csr_val = glbl_get_csr_val_from_op(cpu_resource, ops, i, num_ops, l1_scp, vpu_rf);
      ten_seq[i].op_type = ops[i];
      ten_seq[i].csr_val = csr_val;
   }

   // Pair one Tensor Load TenB with a Tensor FMA TenB
   for (int i = 1; i < num_ops; i++) {
      if ((ten_seq[i-1].op_type == TLOAD_TENB_OP) && (ten_seq[i].op_type == TFMA_TENB_OP)) {
         unum_t tl_bits = snp_get_bits(cpu_resource, ten_seq[i-1].csr_val, 3, 0);
         ten_seq[i].csr_val = snp_set_bits(cpu_resource, ten_seq[i].csr_val, 50, 47, tl_bits);
         break;
      }
   }

   do_fisher_yates(cpu_resource, ten_seq, num_ops, ops);

   // Try to pair Tensor Conv Size with Tensor Conv Ctrl in order to avoid
   // generating Tensor Mask's that are not all 0's or all 1's
   pair_tconv_size_ctrl(cpu_resource, ten_seq, num_ops);

   ret = encode_tensor_ops_sequence(cpu_resource, ops, num_ops);
   return ret;
}

unum_t get_csr_op_type_from_idx(CpuResource * cpu_resource, unum_t idx, unum_t ten_seq_ptr) {
   csr_op *ten_seq = (csr_op*) ten_seq_ptr;
   return ten_seq[idx].op_type;
}

unum_t get_csr_op_value_from_idx(CpuResource * cpu_resource, unum_t idx, unum_t ten_seq_ptr) {
   csr_op *ten_seq = (csr_op*) ten_seq_ptr;
   return ten_seq[idx].csr_val;
}

unum_t get_tensor_waits_from_op(CpuResource * cpu_resource, csr_op operation) {
   unum_t tensor_waits = -1;
   switch (operation.op_type) {
      case TLOAD_OP:
         tensor_waits = get_tload_ten_waits(cpu_resource, operation.csr_val);
         break;
      case TFMA_OP:
         tensor_waits = get_tfma_ten_waits(cpu_resource, operation.csr_val);
         break;
      case TLOAD_TENB_OP:
         tensor_waits = get_tload_ten_waits(cpu_resource, operation.csr_val);
         break;
      case TFMA_TENB_OP:
         tensor_waits = get_tfma_ten_waits(cpu_resource, operation.csr_val);
         break;
      case TQUANT_OP:
         tensor_waits = get_tquant_ten_waits(cpu_resource, operation.csr_val);
         break;
      case TSTORE_OP:
         tensor_waits = get_tstore_ten_waits(cpu_resource, operation.csr_val);
         break;
      case TREDUCE_OP:
         tensor_waits = get_treduce_ten_waits(cpu_resource, operation.csr_val);
         break;
      case TSTORE_SCP_OP:
         tensor_waits = get_ts_scp_ten_waits(cpu_resource, operation.csr_val);
         break;
      case TCONV_SIZE_OP:
         tensor_waits = get_tconv_size_ten_waits(cpu_resource, operation.csr_val);
         break;
      case TCONV_CTRL_OP:
         tensor_waits = get_tconv_ctrl_ten_waits(cpu_resource, operation.csr_val);
         break;
      case TLOAD_L2_OP:
         tensor_waits = get_tload_l2_ten_waits(cpu_resource, operation.csr_val);
         break;
   }
   assert(tensor_waits != -1);
   unum_t tw_enc = 0;
   if (tensor_waits & READS_L1SCP) {
      // TL ID0, TL ID1, TS SCP
      tw_enc = tw_enc | 0x0103;
   }
   if (tensor_waits & WRITES_L1SCP) {
      // TL ID0, TL ID1, TFMA, TQUANT, TSTORE SCP
      tw_enc = tw_enc | 0x0583;
   }
   if (tensor_waits & READS_VPU_RF) {
      // TREDUCE, TFMA, TQUANT
      tw_enc = tw_enc | 0x0680;
   }
   if (tensor_waits & WRITES_VPU_RF) {
      // TREDUCE, TS
      tw_enc = tw_enc | 0x0300;
   }
   if (tensor_waits & READS_FROM_MEM) {
      // TS
      tw_enc = tw_enc | 0x0100;
   }
   if (tensor_waits & WRITES_TO_MEM) {
      // TFMA, TL ID0, TL ID1
      tw_enc = tw_enc | 0x0083;
      /* TFMA is necessary because TL_TENB+TFMA_TENB reads the memory
       * but there is no way to wait for a TL_TENB, therefore we have
       * to wait for the TFMA_TENB
       */
   }
   if (tensor_waits & WAIT_FOR_TFMA) {
      // TFMA
      tw_enc = tw_enc | 0x080;
   }
   return tw_enc;
}

unum_t get_pre_tensor_wait(CpuResource * cpu_resource, unum_t ten_seq_ptr, unum_t num_ops, unum_t tfma_clean_tenb_csr) {
   unum_t ret = 0;
   csr_op *ten_seq = (csr_op*) ten_seq_ptr;
   for (int i = 0; i < num_ops; i++) {
      ret = ret | get_tensor_waits_from_op(cpu_resource, ten_seq[i]);
   }
   if (tfma_clean_tenb_csr != 0) {
      csr_op clean_tenb;
      clean_tenb.op_type = TFMA_TENB_OP;
      clean_tenb.csr_val = tfma_clean_tenb_csr;
      ret = ret | get_tensor_waits_from_op(cpu_resource, clean_tenb);
   }
   return ret;
}

unum_t get_post_tensor_wait(CpuResource * cpu_resource, unum_t ten_seq_ptr, unum_t num_ops, unum_t tfma_clean_tenb_csr, unum_t x31_val) {
   unum_t ret = 0;
   const auto get_post_tw_enc = [x31_val](unum_t op_type) {
      switch (op_type) {
         case TLOAD_OP:
         case TLOAD_TENB_OP:
            return (x31_val & 0x1) ? encode_ten_wait(TEN_WAIT_TL_1) : encode_ten_wait(TEN_WAIT_TL_0);
         case TFMA_OP:
         case TFMA_TENB_OP:
            return encode_ten_wait(TEN_WAIT_TFMA);
         case TQUANT_OP:
            return encode_ten_wait(TEN_WAIT_TQUANT);
         case TSTORE_OP:
         case TSTORE_SCP_OP:
            return encode_ten_wait(TEN_WAIT_TSTORE);
         case TREDUCE_OP:
            return encode_ten_wait(TEN_WAIT_TREDUCE);
         default:
            return 0;
      }
   };
   csr_op *ten_seq = (csr_op*) ten_seq_ptr;
   for (int i = 0; i < num_ops; i++) ret = ret | get_post_tw_enc(ten_seq[i].op_type);
   if (tfma_clean_tenb_csr != 0) ret = ret | get_post_tw_enc(TFMA_TENB_OP);
   return ret;
}

unum_t get_mem_offset_from_idx(CpuResource * cpu_resource, unum_t idx, unum_t ten_seq_ptr, unum_t x31_val) {
   csr_op *ten_seq = (csr_op*) ten_seq_ptr;
   csr_op operation = ten_seq[idx];

   switch (operation.op_type) {
      case TLOAD_OP:
         return get_mem_size_tload(cpu_resource, operation.csr_val, x31_val);
         break;
      case TFMA_OP:
         return get_mem_size_tfma(cpu_resource, operation.csr_val, x31_val);
         break;
      case TLOAD_TENB_OP:
         return get_mem_size_tload(cpu_resource, operation.csr_val, x31_val);
         break;
      case TFMA_TENB_OP:
         return get_mem_size_tfma(cpu_resource, operation.csr_val, x31_val);
         break;
      case TQUANT_OP:
         return get_mem_size_tquant(cpu_resource, operation.csr_val, x31_val);
         break;
      case TSTORE_OP:
         return get_mem_size_tstore(cpu_resource, operation.csr_val, x31_val);
         break;
      case TREDUCE_OP:
         return get_mem_size_treduce(cpu_resource, operation.csr_val, x31_val);
         break;
      case TSTORE_SCP_OP:
         return get_mem_size_ts_scp(cpu_resource, operation.csr_val, x31_val);
         break;
      case TCONV_SIZE_OP:
        return get_mem_size_tconv_size(cpu_resource, operation.csr_val, x31_val);
        break;
      case TCONV_CTRL_OP:
        return get_mem_size_tconv_ctrl(cpu_resource, operation.csr_val, x31_val);
        break;
      case TLOAD_L2_OP:
        return get_mem_size_tload_l2(cpu_resource, operation.csr_val, x31_val);
        break;
   }
   assert(0);
   return -1;
}

unum_t selfcheck_mem_occupation(CpuResource * cpu_resource, unum_t mem_size, unum_t ten_seq_ptr, unum_t num_ops, unum_t x31_val) {
   unum_t mem_occ = 0;

   for (int i = 0; i < num_ops; i++) {
      mem_occ += get_mem_offset_from_idx(cpu_resource, i, ten_seq_ptr, x31_val);
   }
   if (mem_occ > mem_size) {
      assert(mem_occ <= mem_size);
   }
   return mem_occ;
}

unum_t uses_tensor_mask(CpuResource * cpu_resource, unum_t ten_seq_ptr, unum_t num_ops) {
   csr_op *ten_seq = (csr_op*) ten_seq_ptr;

   for (int i = 0; i < num_ops; i++) {
      csr_op operation = ten_seq[i];
      switch (operation.op_type) {
         case TLOAD_OP:
         case TLOAD_TENB_OP:
         case TFMA_OP:
         case TFMA_TENB_OP:
            if ((operation.csr_val & 0x8000000000000000) != 0) {
               return 1;
            }
            break;
         default:
            break;
      }
   }
   return 0;
}

unum_t uses_x31_from_idx(CpuResource * cpu_resource, unum_t idx, unum_t ten_seq_ptr, unum_t num_ops) {
   unum_t ret = 0;
   csr_op *ten_seq = (csr_op*) ten_seq_ptr;
   for (int i = idx; i < num_ops; i++) {
      csr_op operation = ten_seq[i];
      switch (operation.op_type) {
         case TLOAD_OP:
         case TLOAD_TENB_OP:
         case TLOAD_L2_OP:
         case TSTORE_OP:
         case TSTORE_SCP_OP:
            return 1;
         default:
            break;
      }
   }
   return 0;
}

unum_t uses_x31(CpuResource * cpu_resource, unum_t ten_seq_ptr, unum_t num_ops) {
   return uses_x31_from_idx(cpu_resource, 0, ten_seq_ptr, num_ops);
}

unum_t snp_get_tenb_pre_ten_waits(CpuResource * cpu_resource, unum_t tl_enc, unum_t tfma_enc) {
   csr_op tfma;
   tfma.op_type = TFMA_OP;
   tfma.csr_val = tfma_enc;
   unum_t tfma_ten_waits = get_tensor_waits_from_op(cpu_resource, tfma);

   csr_op tl;
   tl.op_type = TLOAD_OP;
   tl.csr_val = tl_enc;
   unum_t tl_ten_waits = get_tensor_waits_from_op(cpu_resource, tl);

   return tfma_ten_waits | tl_ten_waits;
}

unum_t snp_get_tl_l2_pre_ten_waits(CpuResource * cpu_resource, unum_t tl_l2_enc) {
   csr_op tl_l2;
   tl_l2.op_type = TLOAD_L2_OP;
   tl_l2.csr_val = tl_l2_enc;
   return get_tensor_waits_from_op(cpu_resource, tl_l2);
}

// overwrite unpredictable fp registers
unum_t snp_ow_unpr_fregs(CpuResource * cpu_resource, unum_t ten_seq_ptr, unum_t num_ops, unum_t vpu_rf_ptr) {
   csr_op *ten_seq = (csr_op*) ten_seq_ptr;
   unum_t *vpu_rf = (unum_t*) vpu_rf_ptr;

   unum_t unpr_mask = snp_get_unpr_fregs_mask(cpu_resource);

   unum_t ret = 0;
   uint32_t fregs_mask;
   for (int i = 0; i < num_ops; i++) {
      csr_op operation = ten_seq[i];
      switch (operation.op_type) {
         case TQUANT_OP:
            fregs_mask = get_tquant_fregs_mask(cpu_resource, operation.csr_val);
            ret |= (fregs_mask & unpr_mask);
            break;
         case TFMA_OP:
            fregs_mask = get_tfma_fregs_mask(cpu_resource, operation.csr_val);
            ret |= (fregs_mask & unpr_mask);
            break;
         case TREDUCE_OP:
            fregs_mask = get_treduce_fregs_mask(cpu_resource, operation.csr_val);
            ret |= (fregs_mask & unpr_mask);
         case TSTORE_OP:
            fregs_mask = get_tstore_fregs_mask(cpu_resource, operation.csr_val);
            ret |= (fregs_mask & unpr_mask);
         default:
            break;
      }
   }

   return ret;
}
